import{_ as s,o as i,c as a,a3 as n}from"./chunks/framework.CMLpj6w5.js";const u=JSON.parse('{"title":"KI-Agenten","description":"","frontmatter":{},"headers":[],"relativePath":"de/usage/ai-agents.md","filePath":"de/usage/ai-agents.md"}'),t={name:"de/usage/ai-agents.md"};function l(o,e,r,d,h,p){return i(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="ki-agenten" tabindex="-1">KI-Agenten <a class="header-anchor" href="#ki-agenten" aria-label="Permalink to &quot;KI-Agenten&quot;">​</a></h1><p>Deine Aliase leben in Deiner interaktiven Shell. KI-Coding-Agenten wie Claude Code, Codex oder Cursor führen Kommandos in nicht-interaktiven Subshells aus, die Dein Shell-Init nicht laden. Wenn Du also <code>ct = cargo test</code> in einem <code>rust</code>-Profil definiert hast und den Agenten bittest „lass die Tests laufen&quot;, probiert er <code>ct</code> und bekommt <code>command not found</code>.</p><p><code>am context</code> gibt Dein aktives Alias-Set als Markdown aus, das der Agent beim Sitzungsstart einlesen kann. Einmal verdrahtet, expandiert der Agent <code>ct</code> zu <code>cargo test</code>, bevor er es ausführt.</p><h2 id="einrichtung" tabindex="-1">Einrichtung <a class="header-anchor" href="#einrichtung" aria-label="Permalink to &quot;Einrichtung&quot;">​</a></h2><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> context</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --setup</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span></span></code></pre></div><p>Legt <code>~/.claude/settings.json</code> an, falls nicht vorhanden, oder fügt sich in eine vorhandene Datei ein, ohne andere Schlüssel anzutasten. Idempotent: mehrfach ausführen ist sicher.</p><p>Für andere Agenten <code>am context</code> manuell aus deren Session-Start-Hook aufrufen. Siehe die jeweilige Hook-Dokumentation.</p><h2 id="manuelle-einrichtung" tabindex="-1">Manuelle Einrichtung <a class="header-anchor" href="#manuelle-einrichtung" aria-label="Permalink to &quot;Manuelle Einrichtung&quot;">​</a></h2><p>Wenn Du das JSON lieber selbst editierst:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;hooks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;SessionStart&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;matcher&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;startup|clear|compact&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;hooks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;am context&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;async&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Der Matcher <code>&quot;startup|clear|compact&quot;</code> sorgt dafür, dass die Momentaufnahme auch nach <code>/clear</code> und <code>/compact</code> neu injiziert wird. Ohne ihn verliert der Agent Deine Aliase beim ersten Clear.</p><p>Verifiziert mit Claude Code 2.1.126. Siehe <a href="https://code.claude.com/docs/en/hooks" target="_blank" rel="noreferrer">Anthropics Hooks-Dokumentation</a> für die volle Konfigurationsreferenz.</p><h2 id="was-du-in-einer-claude-code-sitzung-siehst" tabindex="-1">Was Du in einer Claude-Code-Sitzung siehst <a class="header-anchor" href="#was-du-in-einer-claude-code-sitzung-siehst" aria-label="Permalink to &quot;Was Du in einer Claude-Code-Sitzung siehst&quot;">​</a></h2><p>Öffne eine neue Sitzung in Deinem Projektverzeichnis. Der Agent sieht jetzt Deine aktiven Aliase, auch die aus aktiven Profilen und aus einer vertrauten <code>.aliases</code>-Datei im Projekt.</p><p>Beispiel: Du hast einen Projekt-Alias <code>t → cargo test --all-features --verbose</code>. Bitte Claude „lass die Tests laufen&quot;. Claude Code sieht <code>t</code> im Kontext, expandiert ihn zu <code>cargo test --all-features --verbose</code> und führt das aus. Der Agent kennt also die Variante von <code>cargo test</code>, die Du in genau diesem Projekt (oder aus einem aktiven Profil) bevorzugst, und muss nicht raten, welche Flags Du willst.</p><p>Subcommand-Aliase funktionieren auch. Etwa mit einem Git-Profil wie:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>├─● git (active: 2)</span></span>
<span class="line"><span>│   ├─ tag → git tag {{1}} &amp;&amp; git push o {{1}}</span></span>
<span class="line"><span>│   ╰─◆ git (subcommands)</span></span>
<span class="line"><span>│     ├─ cm → commit -S --signoff -m</span></span>
<span class="line"><span>│     ├─ pl → pull --rebase</span></span>
<span class="line"><span>│     ├─ psh → push</span></span>
<span class="line"><span>│     ╰─ st → status --short</span></span></code></pre></div><p>Bittest Du Claude Code „zieh die neuesten Änderungen&quot;, sieht es <code>pl</code> im Kontext und expandiert das zu <code>git pull --rebase</code>, bevor es läuft. Bei „commite die Änderungen&quot; entsprechend zur Expansion von <code>git cm</code>. Im Terminal tippst Du die Kurzform, im Chat redest Du natürlich. Claude Code übernimmt die Expansion.</p><h2 id="uberprufung" tabindex="-1">Überprüfung <a class="header-anchor" href="#uberprufung" aria-label="Permalink to &quot;Überprüfung&quot;">​</a></h2><p>In einer frischen Sitzung fragen: <strong>„welche Aliase habe ich?&quot;</strong></p><p>Der Agent sollte sie direkt aus der Momentaufnahme auflisten, ohne ein Kommando auszuführen.</p><p>Oder frag „was würdest Du ausführen, um den Code zu testen?&quot;. Er sollte mit der Expansion Deines <code>t</code>-Alias antworten.</p><p>Wenn nicht, ist der Hook nicht gefeuert. Prüf <code>~/.claude/settings.json</code>.</p><h2 id="hinweise" tabindex="-1">Hinweise <a class="header-anchor" href="#hinweise" aria-label="Permalink to &quot;Hinweise&quot;">​</a></h2><ul><li>Die Markdown-Form von <code>am context</code> ist für ein Modell geschrieben. Die Form kann sich ändern, wenn die Modelle besser werden. Schreib also keine Skripte dagegen.</li><li><code>am context --verbose</code> ergänzt die volle Shadow-Kette und etwaige Diagnosen zu ungültigen Aliasen.</li></ul>`,25)])])}const k=s(t,[["render",l]]);export{u as __pageData,k as default};
